struct LockingTree { black_p: Vec<i32>, black_locked: Vec<i32>, black_children: Vec<Vec<usize>> }impl LockingTree { fn new(p: Vec<i32>) -> Self { let mut c = vec![vec![]; p.len()]; for (i, &v) in p.iter().enumerate() { if v != -1 { c[v as usize].push(i); } } Self { black_p: p, black_locked: vec![-1; c.len()], black_children: c } } fn lock(&mut self, n: i32, u: i32) -> bool { if self.black_locked[n as usize] == -1 { self.black_locked[n as usize] = u; true } else { false } } fn unlock(&mut self, n: i32, u: i32) -> bool { if self.black_locked[n as usize] == u { self.black_locked[n as usize] = -1; true } else { false } } fn upgrade(&mut self, n: i32, u: i32) -> bool { let (mut curr, mut found, mut desc, mut q) = (Some(n as usize), false, vec![], std::collections::VecDeque::from([n as usize])); while let Some(i) = curr { if self.black_locked[i] != -1 { return false; } curr = if self.black_p[i] == -1 { None } else { Some(self.black_p[i] as usize) }; } while let Some(i) = q.pop_front() { for &v in &self.black_children[i] { if self.black_locked[v] != -1 { found = true; } desc.push(v); q.push_back(v); } } if found { self.black_locked[n as usize] = u; for v in desc { self.black_locked[v] = -1; } } found } }